mapper.select:
SELECT id, access_type AS accessType, user_id AS userId, room_id AS roomId, source_tag AS sourceTag,
       automation_log_id AS automationLogId, summary_zh AS summaryZh, detail_zh AS detailZh,
       op_time AS opTime, consumed AS consumed
FROM twin_access_correlation_pending
WHERE consumed = 0
  AND user_id = #{userId}
  AND room_id = #{roomId}
  AND access_type = #{accessType}
  AND op_time >= #{opTimeMin}
  AND op_time <= #{opTimeMax}
ORDER BY op_time ASC, id ASC
LIMIT 1

mapper.update:
UPDATE twin_access_correlation_pending
SET consumed = 1
WHERE id = #{id}
